/**
 * Unit tests for classification session and result initialization utilities
 *
 * Tests the factory functions and update utilities that support the canonical
 * stage signature pattern across the 9-stage classification pipeline.
 */

import {
  createClassificationSession,
  createClassificationResult,
  updateResultWithStageOutput,
  finalizeClassificationSession,
  incrementSessionSuccess,
  incrementSessionError,
  addSessionWarning,
} from '../../src/utils/initialization';
import { ProcessingConfig, ClassificationResult } from '../../src/types';

describe('Initialization Utilities', () => {
  // Mock processing config for testing
  const mockConfig: ProcessingConfig = {
    version: 1,
    taxonomyNotes: 'Test config',
    settings: {
      initialization: {
        applyHardAssertions: true,
        seedCategoryScores: true,
      },
      ruleScoring: {
        useLexicalPatterns: true,
        applySubtypeRules: true,
        boundedAggregation: true,
      },
      attributeProcessing: {
        detectSelfSent: true,
        resolveDomains: true,
        deriveContextFlags: true,
      },
      attributeInfluence: {
        applyBonuses: true,
        applyPenalties: true,
        enforceCaps: true,
      },
      disambiguation: {
        pairwiseAdjustments: true,
        confidenceGapThreshold: 0.15,
      },
      multiLabelSelection: {
        maxLabels: 3,
        minSecondaryConfidence: 0.5,
        allowedCombinations: ['financial+actionable'],
      },
      aiRouting: {
        highConfidenceThreshold: 0.8,
        aiRequiredThreshold: 0.3,
        skipAiConditions: ['hardAssertionPresent'],
      },
    },
    categorySignals: {},
    confidenceThresholds: {
      highConfidence: 0.8,
      mediumConfidence: 0.5,
      lowConfidence: 0.3,
      aiClassificationRequired: 0.3,
      manualReviewRequired: 0.1,
      secondaryLabelMinGap: 0.2,
    },
    multiLabelPolicy: {
      maxTopLevelLabels: 3,
      minConfidenceForAdditional: 0.5,
      minDeltaPrimarySecondary: 0.2,
      allowFinancialActionableCopresence: true,
    },
    domainSignalOverrides: {},
    domainSignalResolution: {
      mode: 'runtimeResolved',
      source: 'config/domain-sources.json',
      notes: 'Test domain resolution',
    },
    topLevelCategories: {},
    attributes: {
      schema: {},
      detectors: [],
      derived: {},
      attributeBonusMap: {},
    },
    attributeRelevance: {
      RolesLegend: {
        CORE: 'Core attribute',
        PRIMARY_BOOST: 'Primary boost',
        SECONDARY_BOOST: 'Secondary boost',
        DISAMBIGUATOR: 'Disambiguator',
        FILTER: 'Filter',
        STRUCTURAL: 'Structural',
        DERIVED_LINK: 'Derived link',
        NEUTRAL: 'Neutral',
      },
    },
    aiPrompts: {
      featureExtraction: {
        systemPrompt: ['Extract features'],
        userPrompt: ['Analyze email'],
      },
      finalClassification: {
        systemPrompt: ['Classify email'],
        userPrompt: ['Determine category'],
      },
    },
    featureExtractionSchema: {
      type: 'object',
      properties: {},
      required: [],
    },
  };

  describe('createClassificationSession', () => {
    it('should create a session with default parallel processing mode', () => {
      const session = createClassificationSession(mockConfig);

      expect(session.id).toBeDefined();
      expect(session.id).toMatch(/^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i); // UUID v4
      expect(session.startedAt).toBeInstanceOf(Date);
      expect(session.completedAt).toBeUndefined();
      expect(session.emailCount).toBe(0);
      expect(session.successCount).toBe(0);
      expect(session.errorCount).toBe(0);
      expect(session.processingMode).toBe('parallel');
      expect(session.batchSize).toBe(0);
    });

    it('should create a session with sequential processing mode when specified', () => {
      const session = createClassificationSession(mockConfig, 'sequential', 10);

      expect(session.processingMode).toBe('sequential');
      expect(session.batchSize).toBe(10);
      expect(session.emailCount).toBe(10);
    });

    it('should initialize performance metrics to zero', () => {
      const session = createClassificationSession(mockConfig);

      expect(session.performanceMetrics).toEqual({
        totalDurationMs: 0,
        avgEmailDurationMs: 0,
        parallelStagesCount: 0,
        databaseBatchOps: 0,
      });
    });

    it('should store config version and snapshot', () => {
      const session = createClassificationSession(mockConfig);

      expect(session.configVersion).toBe('1');
      expect(session.configSnapshot).toEqual(mockConfig);
    });

    it('should initialize empty error and warning arrays', () => {
      const session = createClassificationSession(mockConfig);

      expect(session.errors).toEqual([]);
      expect(session.warnings).toEqual([]);
    });

    it('should generate consistent config hash for same config', () => {
      const session1 = createClassificationSession(mockConfig);
      const session2 = createClassificationSession(mockConfig);

      // Config hash is not exposed in public API, but config snapshots should match
      expect(session1.configSnapshot).toEqual(session2.configSnapshot);
    });
  });

  describe('createClassificationResult', () => {
    it('should create a result with unique ID', () => {
      const result = createClassificationResult('email-123', 'session-456');

      expect(result.id).toBeDefined();
      expect(result.id).toMatch(/^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i); // UUID v4
      expect(result.emailId).toBe('email-123');
      expect(result.sessionId).toBe('session-456');
    });

    it('should initialize empty classification results', () => {
      const result = createClassificationResult('email-123', 'session-456');

      expect(result.primaryCategory).toBe('');
      expect(result.secondaryCategories).toEqual([]);
      expect(result.confidence).toBe(0);
    });

    it('should initialize empty explainability trace with all stage slots', () => {
      const result = createClassificationResult('email-123', 'session-456');

      expect(result.explainabilityTrace).toBeDefined();
      expect(result.explainabilityTrace.hardAssertions).toEqual([]);
      expect(result.explainabilityTrace.strongIndicators).toEqual([]);
      expect(result.explainabilityTrace.ruleScoring).toEqual([]);
      expect(result.explainabilityTrace.attributeDetection).toEqual([]);
      expect(result.explainabilityTrace.attributeInfluence).toEqual([]);
      expect(result.explainabilityTrace.disambiguation).toEqual([]);
      expect(result.explainabilityTrace.multiLabelSelection).toEqual([]);
      expect(result.explainabilityTrace.aiRouting).toBeUndefined();
    });

    it('should initialize empty score breakdown', () => {
      const result = createClassificationResult('email-123', 'session-456');

      expect(result.scoreBreakdown).toBeDefined();
      expect(result.scoreBreakdown.emailId).toBe('');
      expect(result.scoreBreakdown.categoryScores).toEqual({});
      expect(result.scoreBreakdown.stageContributions).toEqual({});
      expect(result.scoreBreakdown.disambiguationApplied).toEqual([]);
    });

    it('should initialize empty attribute context', () => {
      const result = createClassificationResult('email-123', 'session-456');

      expect(result.attributeContext).toBeDefined();
      expect(result.attributeContext.emailId).toBe('');
      expect(result.attributeContext.urgency).toBe('low');
      expect(result.attributeContext.domains).toEqual([]);
      expect(result.attributeContext.derivedAttributes).toEqual({});
    });

    it('should set batch position correctly', () => {
      const result1 = createClassificationResult('email-1', 'session-1', 0);
      const result2 = createClassificationResult('email-2', 'session-1', 5);

      expect(result1.batchPosition).toBe(0);
      expect(result2.batchPosition).toBe(5);
    });

    it('should initialize processing metadata', () => {
      const result = createClassificationResult('email-123', 'session-456');

      expect(result.processedAt).toBeInstanceOf(Date);
      expect(result.processingDurationMs).toBe(0);
      expect(result.aiRoutingUsed).toBe(false);
      expect(result.parallelStageResults).toEqual([]);
    });
  });

  describe('updateResultWithStageOutput', () => {
    let result: ClassificationResult;

    beforeEach(() => {
      result = createClassificationResult('email-123', 'session-456');
    });

    it('should update processing duration', () => {
      const stageResult = {
        processingDurationMs: 15,
      };

      updateResultWithStageOutput(result, stageResult, 'hardAssertions');

      expect(result.processingDurationMs).toBe(15);
    });

    it('should update score breakdown when stage provides updated scores', () => {
      const stageResult = {
        updatedScores: {
          financial: 15,
          actionable: 8,
        },
        processingDurationMs: 25,
      };

      updateResultWithStageOutput(result, stageResult, 'hardAssertions');

      expect(result.scoreBreakdown.categoryScores.financial).toBeDefined();
      expect(result.scoreBreakdown.categoryScores.financial.baseScore).toBe(15);
      expect(result.scoreBreakdown.categoryScores.financial.finalScore).toBe(15);
      expect(result.scoreBreakdown.categoryScores.actionable).toBeDefined();
      expect(result.scoreBreakdown.categoryScores.actionable.baseScore).toBe(8);
      expect(result.scoreBreakdown.categoryScores.actionable.finalScore).toBe(8);
    });

    it('should accumulate processing duration across stages', () => {
      updateResultWithStageOutput(result, { processingDurationMs: 10 }, 'stage1');
      updateResultWithStageOutput(result, { processingDurationMs: 15 }, 'stage2');
      updateResultWithStageOutput(result, { processingDurationMs: 20 }, 'stage3');

      expect(result.processingDurationMs).toBe(45);
    });

    it('should track parallel stage execution metadata', () => {
      const stageResult = {
        parallelExecution: {
          parallelWith: ['attributeDetection_2', 'attributeDetection_3'],
          dependencies: ['hardAssertions', 'strongIndicators'],
          cacheHits: 5,
          errors: 0,
        },
        processingDurationMs: 30,
      };

      updateResultWithStageOutput(result, stageResult, 'attributeDetection');

      expect(result.parallelStageResults).toHaveLength(1);
      expect(result.parallelStageResults[0].stageName).toBe('attributeDetection');
      expect(result.parallelStageResults[0].executionTimeMs).toBe(30);
      expect(result.parallelStageResults[0].parallelWithStages).toEqual([
        'attributeDetection_2',
        'attributeDetection_3',
      ]);
      expect(result.parallelStageResults[0].dependentOnStages).toEqual(['hardAssertions', 'strongIndicators']);
      expect(result.parallelStageResults[0].cacheHitsCount).toBe(5);
      expect(result.parallelStageResults[0].errorCount).toBe(0);
    });

    it('should set AI routing flag when AI stages are used', () => {
      updateResultWithStageOutput(result, { processingDurationMs: 100 }, 'aiRouting');

      expect(result.aiRoutingUsed).toBe(true);
    });

    it('should handle stages without explainability or scores', () => {
      const stageResult = {
        someOtherData: 'value',
      };

      expect(() => {
        updateResultWithStageOutput(result, stageResult, 'customStage');
      }).not.toThrow();
    });
  });

  describe('finalizeClassificationSession', () => {
    it('should set completion timestamp', () => {
      const session = createClassificationSession(mockConfig);
      const startTime = session.startedAt.getTime();

      // Simulate some processing time
      jest.spyOn(Date.prototype, 'getTime').mockReturnValueOnce(startTime + 5000);

      finalizeClassificationSession(session);

      expect(session.completedAt).toBeInstanceOf(Date);
      expect(session.completedAt!.getTime()).toBeGreaterThanOrEqual(startTime);
    });

    it('should calculate total duration correctly', () => {
      const session = createClassificationSession(mockConfig);
      const startTime = session.startedAt.getTime();

      // Mock Date to simulate 5 seconds of processing
      jest.spyOn(Date.prototype, 'getTime').mockReturnValueOnce(startTime + 5000);

      finalizeClassificationSession(session);

      expect(session.performanceMetrics.totalDurationMs).toBe(5000);
    });

    it('should calculate average email duration when emails were processed', () => {
      const session = createClassificationSession(mockConfig);
      session.successCount = 10;
      const startTime = session.startedAt.getTime();

      // Mock Date to simulate 10 seconds of processing
      jest.spyOn(Date.prototype, 'getTime').mockReturnValueOnce(startTime + 10000);

      finalizeClassificationSession(session);

      expect(session.performanceMetrics.avgEmailDurationMs).toBe(1000); // 10000ms / 10 emails
    });

    it('should not calculate average when no successful emails', () => {
      const session = createClassificationSession(mockConfig);
      session.successCount = 0;

      finalizeClassificationSession(session);

      expect(session.performanceMetrics.avgEmailDurationMs).toBe(0);
    });
  });

  describe('incrementSessionSuccess', () => {
    it('should increment success count', () => {
      const session = createClassificationSession(mockConfig);

      expect(session.successCount).toBe(0);

      incrementSessionSuccess(session);
      expect(session.successCount).toBe(1);

      incrementSessionSuccess(session);
      expect(session.successCount).toBe(2);
    });
  });

  describe('incrementSessionError', () => {
    it('should increment error count and record error details', () => {
      const session = createClassificationSession(mockConfig);

      incrementSessionError(session, 'email-123', 'hardAssertions', 'Invalid configuration');

      expect(session.errorCount).toBe(1);
      expect(session.errors).toHaveLength(1);
      expect(session.errors[0]).toMatchObject({
        emailId: 'email-123',
        stage: 'hardAssertions',
        error: 'Invalid configuration',
        recoverable: false,
        retryCount: 0,
      });
      expect(session.errors[0].timestamp).toBeInstanceOf(Date);
    });

    it('should handle Error objects', () => {
      const session = createClassificationSession(mockConfig);
      const error = new Error('Test error message');

      incrementSessionError(session, 'email-456', 'aiRouting', error, true);

      expect(session.errorCount).toBe(1);
      expect(session.errors[0].error).toBe('Test error message');
      expect(session.errors[0].recoverable).toBe(true);
    });

    it('should accumulate multiple errors', () => {
      const session = createClassificationSession(mockConfig);

      incrementSessionError(session, 'email-1', 'stage1', 'Error 1');
      incrementSessionError(session, 'email-2', 'stage2', 'Error 2');
      incrementSessionError(session, 'email-3', 'stage3', 'Error 3');

      expect(session.errorCount).toBe(3);
      expect(session.errors).toHaveLength(3);
    });
  });

  describe('addSessionWarning', () => {
    it('should add warning with default low impact', () => {
      const session = createClassificationSession(mockConfig);

      addSessionWarning(session, 'email-123', 'disambiguation', 'Close scores detected');

      expect(session.warnings).toHaveLength(1);
      expect(session.warnings[0]).toMatchObject({
        emailId: 'email-123',
        stage: 'disambiguation',
        warning: 'Close scores detected',
        impact: 'low',
      });
      expect(session.warnings[0].timestamp).toBeInstanceOf(Date);
    });

    it('should add warning with specified impact level', () => {
      const session = createClassificationSession(mockConfig);

      addSessionWarning(session, 'email-456', 'aiRouting', 'AI quota exceeded', 'high');

      expect(session.warnings).toHaveLength(1);
      expect(session.warnings[0].impact).toBe('high');
    });

    it('should accumulate multiple warnings', () => {
      const session = createClassificationSession(mockConfig);

      addSessionWarning(session, 'email-1', 'stage1', 'Warning 1', 'low');
      addSessionWarning(session, 'email-2', 'stage2', 'Warning 2', 'medium');
      addSessionWarning(session, 'email-3', 'stage3', 'Warning 3', 'high');

      expect(session.warnings).toHaveLength(3);
      expect(session.warnings[0].impact).toBe('low');
      expect(session.warnings[1].impact).toBe('medium');
      expect(session.warnings[2].impact).toBe('high');
    });
  });

  describe('Integration: Full session lifecycle', () => {
    it('should support complete session processing workflow', () => {
      // Create session
      const session = createClassificationSession(mockConfig, 'parallel', 3);
      expect(session.emailCount).toBe(3);

      // Process first email successfully
      const result1 = createClassificationResult('email-1', session.id, 0);
      updateResultWithStageOutput(result1, { updatedScores: { financial: 15 }, processingDurationMs: 50 }, 'stage1');
      incrementSessionSuccess(session);

      // Process second email successfully
      const result2 = createClassificationResult('email-2', session.id, 1);
      updateResultWithStageOutput(result2, { updatedScores: { social: 10 }, processingDurationMs: 45 }, 'stage1');
      incrementSessionSuccess(session);

      // Process third email with error
      incrementSessionError(session, 'email-3', 'stage1', 'Processing failed');

      // Add warning
      addSessionWarning(session, 'email-2', 'stage2', 'Low confidence', 'medium');

      // Simulate time passing before finalizing
      jest.useFakeTimers();
      jest.setSystemTime(new Date(session.startedAt.getTime() + 5000)); // 5 seconds later

      // Finalize session
      finalizeClassificationSession(session);

      jest.useRealTimers();

      // Verify final state
      expect(session.successCount).toBe(2);
      expect(session.errorCount).toBe(1);
      expect(session.warnings).toHaveLength(1);
      expect(session.completedAt).toBeDefined();
      expect(session.performanceMetrics.totalDurationMs).toBe(5000);
      expect(session.performanceMetrics.avgEmailDurationMs).toBe(2500); // 5000ms / 2 successful emails
    });
  });
});

